import React from 'react';
import { motion } from 'framer-motion';
import './FloatingElements.css';

const FloatingElements = () => {
  const circles = [
    { size: 400, duration: 20, delay: 0, x: '5%', y: '15%' },
    { size: 350, duration: 18, delay: 2, x: '75%', y: '55%' },
    { size: 300, duration: 16, delay: 4, x: '65%', y: '5%' },
    { size: 380, duration: 19, delay: 1, x: '15%', y: '65%' },
    { size: 320, duration: 17, delay: 3, x: '45%', y: '35%' },
    { size: 280, duration: 15, delay: 5, x: '85%', y: '25%' },
    { size: 250, duration: 21, delay: 6, x: '30%', y: '80%' },
    { size: 360, duration: 22, delay: 7, x: '55%', y: '10%' }
  ];

  const lines = [
    { width: '3px', height: '250px', x: '12%', duration: 12, delay: 0 },
    { width: '2px', height: '200px', x: '38%', duration: 14, delay: 2 },
    { width: '3px', height: '220px', x: '62%', duration: 16, delay: 4 },
    { width: '2px', height: '180px', x: '78%', duration: 13, delay: 1 },
    { width: '2px', height: '190px', x: '88%', duration: 15, delay: 3 },
    { width: '3px', height: '210px', x: '22%', duration: 17, delay: 5 }
  ];

  return (
    <div className="floating-background">
      {/* Floating circles */}
      {circles.map((circle, index) => (
        <motion.div
          key={index}
          className="floating-circle"
          style={{
            width: circle.size,
            height: circle.size,
            left: circle.x,
            top: circle.y
          }}
          animate={{
            y: [0, -40, 0],
            x: [0, 30, 0],
            scale: [1, 1.15, 1],
            opacity: [0.08, 0.15, 0.08]
          }}
          transition={{
            duration: circle.duration,
            repeat: Infinity,
            ease: "easeInOut",
            delay: circle.delay
          }}
        />
      ))}
      
      {/* Floating vertical lines */}
      {lines.map((line, index) => (
        <motion.div
          key={`line-${index}`}
          className="floating-line"
          style={{
            width: line.width,
            height: line.height,
            left: line.x,
            top: '100vh'
          }}
          animate={{
            y: [0, -1200],
            opacity: [0, 0.3, 0]
          }}
          transition={{
            duration: line.duration,
            repeat: Infinity,
            ease: "linear",
            delay: line.delay
          }}
        />
      ))}
      
      {/* Floating dots */}
      {[...Array(25)].map((_, index) => (
        <motion.div
          key={`dot-${index}`}
          className="floating-dot"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`
          }}
          animate={{
            y: [0, -60, 0],
            opacity: [0.2, 0.5, 0.2]
          }}
          transition={{
            duration: 8 + Math.random() * 8,
            repeat: Infinity,
            ease: "easeInOut",
            delay: Math.random() * 5
          }}
        />
      ))}
      
      {/* Additional floating shapes */}
      {[...Array(8)].map((_, index) => (
        <motion.div
          key={`shape-${index}`}
          className="floating-shape"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`
          }}
          animate={{
            rotate: [0, 360],
            scale: [1, 1.3, 1],
            opacity: [0.1, 0.25, 0.1]
          }}
          transition={{
            duration: 20 + Math.random() * 10,
            repeat: Infinity,
            ease: "easeInOut",
            delay: Math.random() * 5
          }}
        />
      ))}
    </div>
  );
};

export default FloatingElements;
